        browserSessions,
        (row) => `${row.agentSlug}:${row.marketSymbol}`,
        (row) => row._creationTime,
      ),
      browserSessionEvents: browserSessionEvents.sort(
        (a, b) =>
          a._creationTime - b._creationTime || a.sequence - b.sequence,
      ),
      leaderboardSnapshots: leaderboardSnapshots.sort(
        (a, b) => b.capturedAt - a.capturedAt,
      ),
      scanRuns: scanRuns.sort((a, b) => b.startedAt - a.startedAt),
      visionDecisions: latestByKey(
        visionDecisions,
        (row) => `${row.agentSlug}:${row.marketSymbol}`,
        (row) => row.capturedAt,
      ).map((row) => ({
        ...row,
        structureVerdict: row.structureVerdict ?? "none",
        structureStatus: row.structureStatus ?? "none",
      })),
      strategySetups: strategySetups.sort(
        (a, b) => b.lastReviewedAt - a.lastReviewedAt,
      ),
      analysisSchedules: analysisSchedules.sort(
        (a, b) => a.nextReviewAt - b.nextReviewAt,
      ),
      analysisRenderCaches: latestByKey(
        analysisRenderCaches,
        (row) => `${row.agentSlug}:${row.marketSymbol}`,
        (row) => row.reviewedAt,
      ),
      analysisJobs: analysisJobs.sort((a, b) => {
        const left = a.startedAt ?? a.claimedAt ?? a.finishedAt ?? a._creationTime;
        const right = b.startedAt ?? b.claimedAt ?? b.finishedAt ?? b._creationTime;
        return right - left;
      }),
    };
  },
});

