function loadWorkerEnv() {
  const envFiles = [
    ".env.local",
    ".env.development.local",
    ".env",
  ];

  for (const relativePath of envFiles) {
    const fullPath = path.resolve(process.cwd(), relativePath);
    if (!fs.existsSync(fullPath)) continue;

    try {
      process.loadEnvFile(fullPath);
    } catch (error) {
